/// Claude Code 椤圭洰鐩綍鍚嶈鍒欙細姣忎釜闈?ASCII 瀛楁瘝鏁板瓧瀛楃鏇挎崲涓?'-'
pub fn munge_claude_project_dir(cwd: &str) -> String {
    cwd.chars()
        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
        .collect()
