/// 鎸夋渶闀垮墠缂€鍖归厤閲嶆槧灏勮矾寰勶紱鍓╀綑閮ㄥ垎鐨勫垎闅旂杞崲涓虹洰鏍囬鏍笺€?/// 鏃犲尮閰嶈繑鍥?None锛堣皟鐢ㄦ柟璁╃敤鎴锋墜杈擄級銆?pub fn remap_path(path: &str, mappings: &[PathMapping]) -> Option<String> {
    let best = mappings
        .iter()
        .filter(|m| path.starts_with(m.from_prefix.as_str()))
        .max_by_key(|m| m.from_prefix.len())?;
    let rest = &path[best.from_prefix.len()..];
    // 鐩爣鏄?Windows 椋庢牸锛堝舰濡?"X:\..."锛夌敤 '\'锛屽惁鍒欑敤 '/'
    let target_sep = if best.to_prefix.get(1..3) == Some(":\\") { '\\' } else { '/' };
    let rest_converted: String = rest
        .chars()
        .map(|c| if c == '\\' || c == '/' { target_sep } else { c })
        .collect();
    Some(format!("{}{}", best.to_prefix, rest_converted))
}
