use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum SessionSource {
    Codex,
    ClaudeCode,
}

/// 本机扫描出的一个会话（不落盘，仅内存与 IPC）
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SessionSummary {
    pub session_id: String,
    pub source: SessionSource,
    pub cwd: String,
    /// 本机会话文件绝对路径
    pub transcript_path: String,
    /// 恢复时需要的原始相对路径：
    /// codex 是 "2026/06/21/rollout-....jsonl"，claude 是 "<munged-dir>/<id>.jsonl"
    pub relative_store_path: String,
    /// 第一条真实用户消息，截断 200 字符，作为默认标题
    pub first_message: String,
    pub message_count: u32,
    pub started_at: String,
    pub last_active_at: String,
}

/// 同步仓库中 sessions/<id>/meta.json 的内容（数据真身）
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SessionMeta {
    pub schema_version: u32,
    pub session_id: String,
    pub source: SessionSource,
    pub title: String,
    #[serde(default)]
    pub description: String,
    #[serde(default)]
    pub tags: Vec<String>,
    #[serde(default)]
    pub starred: bool,
    pub origin_device_id: String,
    pub origin_cwd: String,
    pub relative_store_path: String,
    pub started_at: String,
    pub last_active_at: String,
    /// ISO8601，整文件 last-write-wins 的比较键
    pub updated_at: String,
}

impl SessionMeta {
    /// 从扫描结果初始化一份 meta（首次上传时用）
    pub fn from_summary(s: &SessionSummary, device_id: &str, now_iso: &str) -> SessionMeta {
        SessionMeta {
            schema_version: 1,
            session_id: s.session_id.clone(),
            source: s.source,
            title: s.first_message.clone(),
            description: String::new(),
            tags: vec![],
            starred: false,
            origin_device_id: device_id.to_string(),
            origin_cwd: s.cwd.clone(),
            relative_store_path: s.relative_store_path.clone(),
            started_at: s.started_at.clone(),
            last_active_at: s.last_active_at.clone(),
            updated_at: now_iso.to_string(),
        }
    }
}

