import { useState } from "react";
import { SessionMeta, SessionSummary, api } from "../api";

const badge = (source: string) => (source === "codex" ? "🟢 Codex" : "🟠 Claude");

export function LocalList({ sessions, onUploaded }: {
  sessions: SessionSummary[];
  onUploaded: () => void;
}) {
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [busy, setBusy] = useState(false);

  const toggle = (id: string) => {
    const next = new Set(selected);
    next.has(id) ? next.delete(id) : next.add(id);
    setSelected(next);
  };

  const upload = async () => {
    setBusy(true);
    try {
      const n = await api.uploadSessions([...selected]);
      alert(`已上传 ${n} 个会话`);
      setSelected(new Set());
      onUploaded();
    } catch (e) {
      alert(`上传失败：${e}`);
    } finally {
      setBusy(false);
    }
  };

  return (
    <div>
      <button disabled={selected.size === 0 || busy} onClick={upload}>
        上传选中（{selected.size}）
      </button>
      <ul className="session-list">
        {sessions.map((s) => (
          <li key={s.session_id}>
            <label>
              <input
                type="checkbox"
                checked={selected.has(s.session_id)}
                onChange={() => toggle(s.session_id)}
              />
              <span>{badge(s.source)}</span>
              <strong>{s.first_message || "(无标题)"}</strong>
              <small>
                {s.cwd} · {s.message_count} 条 · {s.last_active_at.slice(0, 16)}
              </small>
            </label>
          </li>
        ))}
      </ul>
    </div>
  );
}

export function RepoList({ metas, onChanged, onRestore }: {
  metas: SessionMeta[];
  onChanged: () => void;
  onRestore: (meta: SessionMeta) => void;
}) {
  const save = async (meta: SessionMeta, patch: Partial<SessionMeta>) => {
    try {
      await api.updateSessionMeta({ ...meta, ...patch });
      onChanged();
    } catch (e) {
      alert(`保存失败：${e}`);
    }
  };

  return (
    <ul className="session-list">
      {metas.map((m) => (
        <li key={m.session_id}>
          <button onClick={() => save(m, { starred: !m.starred })}>
            {m.starred ? "★" : "☆"}
          </button>
          <span>{badge(m.source)}</span>
          <input
            defaultValue={m.title}
            onBlur={(e) => e.target.value !== m.title && save(m, { title: e.target.value })}
          />
          <input
            placeholder="描述…"
            defaultValue={m.description}
            onBlur={(e) =>
              e.target.value !== m.description && save(m, { description: e.target.value })
            }
          />
          <small>{m.origin_cwd}</small>
          <button onClick={() => onRestore(m)}>恢复到本机</button>
        </li>
      ))}
    </ul>
  );
}
