import { useEffect, useState } from "react";
import { SessionMeta, api } from "../api";

export function RestoreDialog({ meta, onClose, onDone }: {
  meta: SessionMeta;
  onClose: () => void;
  onDone: () => void;
}) {
  const [target, setTarget] = useState("");
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    // 用设备路径映射预填目标路径，映射不到就留给用户手输
    api.suggestRestorePath(meta.session_id).then((p) => setTarget(p ?? meta.origin_cwd));
  }, [meta.session_id]);

  const restore = async () => {
    setBusy(true);
    try {
      const dest = await api.restoreSession(meta.session_id, target);
      alert(`已恢复到：${dest}\n在 ${meta.source === "codex" ? "Codex" : "Claude Code"} 中打开该项目即可看到会话。`);
      onDone();
    } catch (e) {
      alert(`恢复失败：${e}`);
      setBusy(false);
    }
  };

  return (
    <div className="dialog-backdrop">
      <div className="dialog">
        <h3>恢复会话：{meta.title}</h3>
        <p>原路径：{meta.origin_cwd}</p>
        <label>
          本机项目路径：
          <input value={target} onChange={(e) => setTarget(e.target.value)} size={50} />
        </label>
        <div>
          <button onClick={restore} disabled={!target || busy}>恢复</button>
          <button onClick={onClose} disabled={busy}>取消</button>
        </div>
      </div>
    </div>
  );
}
```

