import { useEffect, useState } from "react";
import { PathMapping, api } from "../api";

export function SettingsPanel() {
  const [deviceId, setDeviceId] = useState("");
  const [repoUrl, setRepoUrl] = useState("");
  const [mappings, setMappings] = useState<PathMapping[]>([]);
  const [status, setStatus] = useState("");

  useEffect(() => {
    api.getSettings().then((s) => {
      setDeviceId(s.device_id);
      setRepoUrl(s.repo_url ?? "");
      setMappings(s.path_mappings);
    });
  }, []);

  const save = async () => {
    setStatus("保存中…");
    try {
      await api.saveSettings(repoUrl || null, mappings.filter((m) => m.from_prefix && m.to_prefix));
      setStatus("已保存 ✓");
    } catch (e) {
      setStatus(`保存失败：${e}`);
    }
  };

  const setMapping = (i: number, key: keyof PathMapping, value: string) => {
    const next = mappings.slice();
    next[i] = { ...next[i], [key]: value };
    setMappings(next);
  };

  return (
    <div>
      <p>设备 ID：<code>{deviceId}</code></p>
      <label>
        同步仓库（GitHub 私有仓库，SSH 或 HTTPS，凭据用系统 git 的）：
        <input
          value={repoUrl}
          onChange={(e) => setRepoUrl(e.target.value)}
          placeholder="git@github.com:me/ai-sessions.git"
          size={50}
        />
      </label>
      <h4>路径映射（其他设备路径前缀 → 本机路径前缀）</h4>
      {mappings.map((m, i) => (
        <div key={i}>
          <input
            value={m.from_prefix}
            onChange={(e) => setMapping(i, "from_prefix", e.target.value)}
            placeholder="E:\fromGithub"
          />
          →
          <input
            value={m.to_prefix}
            onChange={(e) => setMapping(i, "to_prefix", e.target.value)}
            placeholder="/Users/me/code"
          />
          <button onClick={() => setMappings(mappings.filter((_, j) => j !== i))}>删</button>
        </div>
      ))}
      <button onClick={() => setMappings([...mappings, { from_prefix: "", to_prefix: "" }])}>
        + 加一条映射
      </button>
      <div>
        <button onClick={save}>保存</button> <span>{status}</span>
      </div>
    </div>
  );
}
